;  end ; _erbout.<< "\n\n<script>\ndocument.addEventListener('DOMContentLoaded', function() {\n    // Add interactive animations to form elements\n    const formControls = document.querySelectorAll('.form-control, .form-select');\n    formControls.forEach(control => {\n        control.addEventListener('focus', function() {\n            this.parentElement.style.transform = 'scale(1.02)';\n            this.parentElement.style.transition = 'transform 0.3s ease';\n        });\n        \n        control.addEventListener('blur', function() {\n            this.parentElement.style.transform = 'scale(1)';\n        });\n    });\n\n    // Add ripple effect to buttons\n    const buttons = document.querySelectorAll('.btn-register, .signup-btn');\n    buttons.forEach(button => {\n        button.addEventListener('click', function(e) {\n            const ripple = document.createElement('span');\n            const rect = this.getBoundingClientRect();\n            const size = Math.max(rect.width, rect.height);\n            const x = e.clientX - rect.left - size / 2;\n            const y = e.clientY - rect.top - size / 2;\n            \n            ripple.style.width = ripple.style.height = size + 'px';\n            ripple.style.left = x + 'px';\n            ripple.style.top = y + 'px';\n            ripple.classList.add('ripple');\n            \n            this.appendChild(ripple);\n            \n            setTimeout(() => {\n                ripple.remove();\n            }, 600);\n        });\n    });\n\n    // Add floating animation to shapes\n    const shapes = document.querySelectorAll('.shape');\n    shapes.forEach((shape, index) => {\n        shape.style.animationDelay = (index * 2) + 's';\n    });\n\n    // Add typing animation to welcome text\n    const welcomeTitle = document.querySelector('.welcome-title');\n    if (welcomeTitle) {\n        const text = welcomeTitle.textContent;\n        welcomeTitle.textContent = '';\n        let i = 0;\n        const typeWriter = () => {\n            if (i < text.length) {\n                welcomeTitle.textContent += text.charAt(i);\n                i++;\n                setTimeout(typeWriter, 100);\n            }\n        };\n        setTimeout(typeWriter, 1000);\n    }\n\n    // Add user addition animation\n    const userAddIcon = document.querySelector('.user-add-icon');\n    if (userAddIcon) {\n        userAddIcon.addEventListener('mouseenter', function() {\n            this.style.transform = 'scale(1.1) rotate(5deg)';\n            this.style.transition = 'transform 0.3s ease';\n        });\n        \n        userAddIcon.addEventListener('mouseleave', function() {\n            this.style.transform = 'scale(1) rotate(0deg)';\n        });\n    }\n\n    // Add form validation animations\n    const form = document.querySelector('form');\n    if (form) {\n        form.addEventListener('submit', function(e) {\n            const requiredFields = form.querySelectorAll('[required]');\n            let hasErrors = false;\n            \n            requiredFields.forEach(field => {\n                if (!field.value.trim()) {\n                    field.style.borderColor = '#dc2626';\n                    field.style.animation = 'shake 0.5s ease-in-out';\n                    hasErrors = true;\n                    \n                    setTimeout(() => {\n                        field.style.borderColor = '#e5e7eb';\n                        field.style.animation = '';\n                    }, 500);\n                }\n            });\n            \n            if (hasErrors) {\n                e.preventDefault();\n            }\n        });\n    }\n});\n\n// Add CSS for ripple effect and shake animation\n(function() {\n    // Check if style already exists to avoid Turbo conflicts\n    let styleElement = document.getElementById('registration-style');\n    if (!styleElement) {\n        styleElement = document.createElement('style');\n        styleElement.id = 'registration-style';\n        styleElement.textContent = `\n    .ripple {\n        position: absolute;\n        border-radius: 50%;\n        background: rgba(255, 255, 255, 0.6);\n        transform: scale(0);\n        animation: ripple-animation 0.6s linear;\n        pointer-events: none;\n    }\n    \n    @keyframes ripple-animation {\n        to {\n            transform: scale(4);\n            opacity: 0;\n        }\n    }\n    \n    @keyframes shake {\n        0%, 100% { transform: translateX(0); }\n        25% { transform: translateX(-5px); }\n        75% { transform: translateX(5px); }\n    }\n    \n    .btn-register, .signup-btn {\n        position: relative;\n        overflow: hidden;\n    }\n    \n    .user-add-icon {\n        cursor: pointer;\n        transition: transform 0.3s ease;\n    }\n`;\n        document.head.appendChild(styleElement);\n    }\n})();\n</script>\n\n".freeze


















































































































































